def enhanced_heuristic(board: Board, boxes: tuple[Pos, ...]) -> int:
    """Greedy matching + mobility penalty (mirrors Rust enhanced_heuristic)."""
    base = greedy_matching(board, boxes)
    goal_set = frozenset(board.goals)
    box_set = frozenset(boxes)
    penalty = 0
    for bx in boxes:
        if bx in goal_set:
            continue
        blocked = 0
        for dx, dy in DIRECTIONS:
            nb = Pos(bx.x + dx, bx.y + dy)
            if nb in board.walls or nb in box_set:
                blocked += 1
        if blocked >= 3:
            penalty += 10
        elif blocked == 2:
            penalty += 2
    return base + penalty

def heuristic(board, boxes):
    """
    Admissible heuristic: optimal assignment of boxes to goals using
    static shortest‑push distances (ignoring other boxes).  If a box
    cannot reach any goal (dead‑locked), return a large value.
    """
    # Pre‑compute distance maps from each goal to every reachable cell.
    if not hasattr(board, "_goal_dist_maps"):
        from collections import deque

        goal_maps = []
        for goal in board.goals:
            dist = {goal: 0}
            q = deque([goal])
            while q:
                p = q.popleft()
                d = dist[p]
                for dx, dy in [(0, -1), (1, 0), (0, 1), (-1, 0)]:
                    np = board.Pos(p.x + dx, p.y + dy) if hasattr(board, "Pos") else None
                    if np is None:
                        np = type(p)(p.x + dx, p.y + dy)  # fallback Pos construction
                    if np.x < 0 or np.y < 0 or np.x >= board.width or np.y >= board.height:
                        continue
                    if np in board.walls:
                        continue
                    if np not in dist:
                        dist[np] = d + 1
                        q.append(np)
            goal_maps.append(dist)
        board._goal_dist_maps = goal_maps

    m = len(board.goals)
    n = len(boxes)
    INF = 10 ** 9

    # Cost matrix: pushes needed for box i to goal j (ignoring other boxes)
    cost = [[INF] * m for _ in range(n)]
    for i, b in enumerate(boxes):
        for j, gmap in enumerate(board._goal_dist_maps):
            d = gmap.get(b, INF)
            cost[i][j] = d

    # DP over subsets of goals to find minimal sum of distances (optimal matching)
    dp = [INF] * (1 << m)
    dp[0] = 0
    for i in range(n):
        newdp = [INF] * (1 << m)
        for mask in range(1 << m):
            cur = dp[mask]
            if cur == INF:
                continue
            for j in range(m):
                if mask & (1 << j):
                    continue
                d = cost[i][j]
                if d == INF:
                    continue
                nmask = mask | (1 << j)
                val = cur + d
                if val < newdp[nmask]:
                    newdp[nmask] = val
        dp = newdp

    best = dp[(1 << m) - 1]

    # If any box cannot reach any goal (deadlock), push heuristic high
    if best >= INF // 2:
        return 1000

    return int(best)
